const item = $input.first();
const sourceLinks = Array.isArray(item.json.links) ? item.json.links : [];

function normalizeLink(rawLink) {
  const link = String(rawLink ?? '').trim();
  if (!link) return null;

  try {
    const url = new URL(link);
    const jobMatch = url.pathname.match(/\/jobs\/view\/(\d+)/i);

    if (jobMatch) {
      return `https://www.linkedin.com/jobs/view/${jobMatch[1]}`;
    }

    url.search = '';
    url.hash = '';
    return url.toString().replace(/\/$/, '');
  } catch {
    return link.replace(/[?#].*$/, '').replace(/\/$/, '');
  }
}

const seen = new Set();
const uniqueLinks = [];

for (const rawLink of sourceLinks) {
  const normalizedLink = normalizeLink(rawLink);

  if (!normalizedLink || seen.has(normalizedLink)) {
    continue;
  }

  seen.add(normalizedLink);
  uniqueLinks.push(normalizedLink);
}

return [{ json: { ...item.json, links: uniqueLinks } }];

const input = $input.first().json;
const source = "gemini";

function toRaw(value) {
  if (value == null) return "";
  if (typeof value === "string") return value;
  try {
    return JSON.stringify(value);
  } catch (error) {
    return String(value);
  }
}

function parseJsonLike(text) {
  const cleaned = String(text || "")
    .replace(/```json/gi, "")
    .replace(/```/g, "")
    .trim();

  const match = cleaned.match(/\{[\s\S]*\}/);
  if (!match) return null;

  try {
    return JSON.parse(match[0]);
  } catch (error) {
    return null;
  }
}

let parsed = null;

if (input.output && typeof input.output === "object") {
  parsed = input.output;
} else {
  const raw = input.output ?? input.text ?? input.response ?? input.content ?? input;
  parsed = parseJsonLike(toRaw(raw));
}

const numericScore = Number(parsed?.score);
const score = Number.isFinite(numericScore)
  ? Math.max(0, Math.min(100, Math.round(numericScore)))
  : -1;

return [{
  json: {
    score,
    scoreValid: score >= 0 ? 1 : 0,
    scoreSource: source,
    scoringError: score >= 0 ? "" : `Invalid score output from ${source}`,
    rawModelOutput: toRaw(input.output ?? input.text ?? input.response ?? input.content ?? input)
  }
}];

