const input = $input.first().json;

const keyword = (input.Keyword || "").trim();
const location = (input.Location || "").trim();
const experienceLevel = (input["Experience Level"] || "").trim();
const remote = (input.Remote || "").trim();
const jobType = (input["Job Type"] || "").trim();
const easyApply = input["Easy Apply"];
const start = input.Start ?? 0;

// GEO MAP
const geoMap = {
  india: "102713980",
  chennai: "106888327",
  bengaluru: "105214831",
  bangalore: "105214831",
  hyderabad: "104869687",
  mumbai: "106164952",
  delhi: "115918471"
};

// PARAMS OBJECT
const params = [];

// always add this
params.push("f_TPR=r86400");

// KEYWORD
if (keyword) {
  const cleanKeyword = keyword
    .replace(/\n/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  params.push(`keywords=${encodeURIComponent(cleanKeyword)}`);
}

// LOCATION + GEOID
if (location) {
  const loc = location.toLowerCase();

  params.push(`location=${encodeURIComponent(location)}`);

  if (geoMap[loc]) {
    params.push(`geoId=${geoMap[loc]}`);
  }
}

// EXPERIENCE
if (experienceLevel) {
  const expMap = {
    "Internship": "1",
    "Entry Level": "2",
    "Associate": "3",
    "Mid-Senior level": "4",
    "Director": "5",
    "Executive": "6"
  };

  const values = experienceLevel
    .split(",")
    .map(e => expMap[e.trim()])
    .filter(Boolean);

  if (values.length) {
    params.push(`f_E=${values.join(",")}`);
  }
}

// REMOTE
if (remote) {
  const remoteMap = {
    "On-Site": "1",
    "Remote": "2",
    "Hybrid": "3"
  };

  const values = remote
    .split(",")
    .map(r => remoteMap[r.trim()])
    .filter(Boolean);

  if (values.length) {
    params.push(`f_WT=${values.join(",")}`);
  }
}

// JOB TYPE
if (jobType) {
  const jobMap = {
    "Full-time": "F",
    "Part-time": "P",
    "Contract": "C",
    "Temporary": "T",
    "Volunteer": "V",
    "Internship": "I",
    "Other": "O"
  };

  const values = jobType
    .split(",")
    .map(j => jobMap[j.trim()])
    .filter(Boolean);

  if (values.length) {
    params.push(`f_JT=${values.join(",")}`);
  }
} else if (/intern/i.test(keyword)) {
  // AUTO FIX
  params.push("f_JT=I");
}

// EASY APPLY (optional)
if (easyApply === true || easyApply === "true") {
  params.push("f_AL=true");
}

// PAGINATION
params.push(`start=${start}`);

// FINAL URL
const url = `https://www.linkedin.com/jobs/search?${params.join("&")}&f_TPR=86400`;

return [{ json: { url } }];
